#include <Servo.h>

const int TRIG_PIN = 7;
const int ECHO_PIN = 8;
const int SERVO_PIN = 9;
const int CLOSE_DISTANCE_CM = 25;

Servo waveServo;

void setup() {
  Serial.begin(9600);
  pinMode(TRIG_PIN, OUTPUT);
  pinMode(ECHO_PIN, INPUT);
  waveServo.attach(SERVO_PIN);
  waveServo.write(90);
}

long readDistanceCm() {
  digitalWrite(TRIG_PIN, LOW);
  delayMicroseconds(2);
  digitalWrite(TRIG_PIN, HIGH);
  delayMicroseconds(10);
  digitalWrite(TRIG_PIN, LOW);
  long durationUs = pulseIn(ECHO_PIN, HIGH, 30000);
  if (durationUs == 0) return -1;
  return durationUs / 58;
}

void wave() {
  for (int angle = 60; angle <= 120; angle += 5) {
    waveServo.write(angle);
    delay(15);
  }
  for (int angle = 120; angle >= 60; angle -= 5) {
    waveServo.write(angle);
    delay(15);
  }
}

void loop() {
  long cm = readDistanceCm();
  if (cm > 0 && cm < CLOSE_DISTANCE_CM) {
    wave();
  }
  delay(100);
}
